INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (5, 'Brava (BRAV3): suspensão de oferta da Ecopetrol adiciona incerteza no curto prazo', 'Ecopetrol discordou de determinados requisitos técnicos impostos pela Comissão de Valores Mobiliários (CVM) The post Brava (BRAV3): suspensão de oferta da Ecopetrol adiciona incerteza no curto prazo appeared first on InfoMoney .', 'https://www.infomoney.com.br/mercados/brava-brav3-suspensao-de-oferta-da-ecopetrol-adiciona-incerteza-no-curto-prazo/', 'InfoMoney', '2026-06-17T14:36:43', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (12, 'Cooperativas são reconhecidas como manifestação da cultura nacional', 'A partir desta quarta-feira (17), o cooperativismo é reconhecido como manifestação da cultura nacional e poderá acessar recursos de fundos regionais de desenvolvimento. As duas normas que fortalecem o setor estão publicadas no Diário Oficial da União . A Lei nº 15.433 , além de considerar o setor parte do conjunto cultural brasileiro, determina que o Estado garanta a livre atividade das cooperativas e apoie o modelo, conforme previsto na Constituição Federal . Notícias relacionadas: Cooperativismo inclui pequenos produtores no mercado, diz ex-ministro. Alckmin defende fortalecimento do coopera…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/cooperativas-sao-reconhecidas-como-manifestacao-da-cultura-nacional', 'Agencia Brasil - Economia', '2026-06-17T13:12:00', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (13, 'Programa destina R$ 360 milhões a pequenas empresas inovadoras', 'O Ministério da Ciência, Tecnologia e Inovação (MCTI) e a Financiadora de Estudos e Projetos (Finep) lançaram nesta terça-feira (16), no Rio de Janeiro, o Programa Tecnova 2026/2027. A iniciativa oferece R$ 360 milhões para pequenas empresas do país desenvolverem produtos, serviços e processos inovadores. Os recursos são da Finep e do Fundo Nacional de Desenvolvimento Científico e Tecnológico (FNDCT). É a quarta edição do programa, que desta vez planeja contratar até 713 empresas com faturamento anual de até R$ 16 milhões . O total de recursos investidos pode chegar a R$ 588 milhões se forem c…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/programa-destina-r-360-milhoes-pequenas-empresas-inovadoras', 'Agencia Brasil - Economia', '2026-06-16T22:39:00', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (16, 'Copom avalia indicadores econômicos e decide sobre Selic', 'O Comitê de Política Monetária (Copom) do Banco Central (BC) se reúne nesta terça (16) e quarta-feira para decidir sobre a taxa básica de juros, a Selic, atualmente em 14,5%. O Copom vai avaliar os indicadores da economia brasileira e global e deliberar se há espaço para uma queda nos juros ou se a taxa permanecerá elevada por mais tempo. Na última reunião, em abril, por unanimidade, o Copom cortou os juros em 0,25 ponto percentual . Essa foi a segunda vez seguida que o comitê reduziu os juros, mas o corte ocorreu em ritmo menor. Como justificativa, foram apontadas as incertezas sobre os desdo…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/copom-avalia-indicadores-economicos-e-decide-sobre-selic', 'Agencia Brasil - Economia', '2026-06-16T11:02:00', 8, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (18, 'União paga R$ 834,8 milhões em dívidas de estados e municípios em maio', 'A União pagou R$ 834,8 milhões em dívidas atrasadas de estados e municípios em maio deste ano, segundo o Relatório de Garantias Honradas pela União em Operações de Crédito e Recuperação de Contragarantias , divulgado nesta segunda-feira (15) pelo Tesouro Nacional. Em 2026, o valor já chega a R$ 2,2 bilhões de dívidas de entes federados honradas pela União. Os estados que precisaram de cobertura do Tesouro Nacional no mês passado foram: Notícias relacionadas: União paga R$ 10,95 bilhões de dívidas de estados. Tesouro paga R$ 257,7 mi em dívidas de estados e municípios em janeiro. Tesouro Nacion…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/uniao-paga-r-8348-milhoes-em-dividas-de-estados-e-municipios-em-maio', 'Agencia Brasil - Economia', '2026-06-15T19:51:00', 7, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (19, 'Brasil desenvolve sensor de freio automático que pode ser obrigatório', 'Pesquisadores de universidades, institutos de pesquisa e empresas do setor automotivo desenvolvem, aqui no Brasil, um sensor nacional para sistemas de frenagem automática, que poderá ser obrigatório em todos os veículos fabricados a partir de 1º de janeiro de 2029. A tecnologia é um sensor de radar chamado sistema Adas, sigla para Advanced Driver Assistance Systems (Sistemas Avançados de Assistência ao Motorista, em inglês). Esse sistema vai reforçar a segurança dos veículos ao viabilizar recursos como frenagem automática e assistência de permanência em faixa. Notícias relacionadas: Tarifa zer…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/brasil-desenvolve-sensor-de-freio-automatico-que-pode-ser-obrigatorio', 'Agencia Brasil - Economia', '2026-06-15T17:00:00', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (20, 'Mercado financeiro eleva previsão da Selic para 13,75% ao ano', 'Pela segunda semana seguida, às vésperas da reunião do Comitê de Política Monetária (Copom) do Banco Central (BC), o mercado financeiro elevou a estimativa para a taxa básica de juros, a Selic. A previsão dos analistas para os juros, até o final de 2026, passou de 13,5% ao ano para 13,75% ao ano. A informação está no boletim Focus desta segunda-feira (16), pesquisa divulgada semanalmente pelo BC com a expectativa de instituições financeiras para os principais indicadores econômicos. Notícias relacionadas: Mercado financeiro eleva previsão da inflação para 5,11% este ano. INPC, inflação usada p…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/mercado-financeiro-eleva-previsao-da-selic-para-1375-ao-ano', 'Agencia Brasil - Economia', '2026-06-15T13:10:00', 10, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (21, 'Transnordestina já tem mais de 100 quilômetros de malha concluídos', 'A Ferrovia Transnordestina alcançou um recorde em sua construção ao registrar o maior ritmo diário de montagem desde o início das obras, no último domingo (7). Na ocasião, as equipes concluíram 1,69 quilômetro de ferrovia em um único dia, durante a instalação de 3,36 quilômetros de trilhos no Lote 5, em Quixeramobim (CE). Notícias relacionadas: Governo ampliará trecho da ferrovia Transnordestina em Pernambuco. Governo vai defender retomada de obras da Transnordestina junto ao TCU. Segundo o Ministério da Integração e do Desenvolvimento Regional, a obra já tem mais 100 quilômetros de ferrovia c…', 'https://agenciabrasil.ebc.com.br/economia/noticia/2026-06/transnordestina-ja-tem-mais-de-100-quilometros-de-malha-concluidos', 'Agencia Brasil - Economia', '2026-06-12T23:19:00', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (32, 'Por que um El Niño intenso deixa safras tropicais vulneráveis', 'Previsões para o El Niño estão mudando a produção no campo Previsões para o El Niño estão mudando a produção no campo É cada vez mais provável que um super El Niño se desenvolva no segundo semestre do ano, elevando as temperaturas, alterando o regime de chuvas e trazendo riscos para as safras em todo o mundo. Entenda nesta reportagem o que é o El Niño e por que algumas safras em regiões tropicais estão expostas. O que é o El Niño? O El Niño é um aquecimento periódico da superfície do mar no Pacífico oriental, causado pelo enfraquecimento dos ventos alísios, e que ocorre naturalmente a cada doi…', 'https://g1.globo.com/economia/agronegocios/noticia/2026/06/17/por-que-um-el-nino-intenso-deixa-safras-tropicais-vulneraveis.ghtml', 'G1 Economia', '2026-06-17T13:01:16', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (33, '''Prévia do PIB'' do Banco Central tem alta de 0,5% em abril', 'O Índice de Atividade Econômica (IBC-Br), divulgado pelo Banco Central do Brasil (BC) nesta quarta-feira (17), mostrou expansão de 0,5% em abril, na comparação com o mês anterior. O cálculo é feito após ajuste sazonal — ou seja, uma forma de comparar períodos diferentes. O resultado representa melhora em relação a março, quando houve retração de 0,2% no indicador. Foi o maior aumento desde fevereiro, quando foi registrada alta de 0,6%. Veja abaixo o desempenho setor por setor em abril: agropecuária: estabilidade; indústria: alta de 0,4%; serviços: crescimento de 0,3%. Agora no g1 Ainda segundo…', 'https://g1.globo.com/economia/noticia/2026/06/17/previa-do-pib-do-banco-central-tem-alta-de-05percent-em-abril.ghtml', 'G1 Economia', '2026-06-17T12:01:10', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (34, 'Dólar opera em queda com decisões de juros do Brasil e dos EUA no foco; Ibovespa avança', 'Entenda o que faz o preço do dólar subir ou cair Após iniciar a sessão desta quarta-feira (17) em alta, o dólar inverteu o sinal e passou a cair. Perto das 11h, a moeda americana recuava 0,36%, a R$ 5,0677, enquanto o Ibovespa, principal índice da bolsa brasileira, avançava 0,73%, aos 170.884 pontos. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 ▶️ A "Superquarta", momento em que os bancos centrais do Brasil e dos EUA devem anunciar suas decisões de juros, é o principal destaque da sessão. O mercado espera a manutenção da taxa básica americana por parte do Federal Reserve (Fed, o BC do…', 'https://g1.globo.com/economia/noticia/2026/06/17/dolar-ibovespa.ghtml', 'G1 Economia', '2026-06-17T12:00:35', 14, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (37, 'Sem reunião formal entre Lula e Trump no G7, tarifaço segue na mira do governo e reforça estratégia de pressão dos EUA', 'Lula e Donald Trump em foto de família da cúpula do G7 em Evián, na França, em 16 de junho de 2026. Evelyn Hockstein/ Reuters A negociação das novas tarifas impostas pelo presidente dos Estados Unidos, Donald Trump, no início de junho está entre as principais prioridades do governo brasileiro. Havia expectativa de que o presidente Luiz Inácio Lula da Silva (PT) conseguisse algum encontro com o líder americano no encontro do G7, grupo das sete maiores economias do mundo, realizado na França nesta semana. Segundo apuração da TV Globo, os dois chegaram a conversar brevemente na noite de ontem, ma…', 'https://g1.globo.com/economia/noticia/2026/06/17/tarifaco-de-trump-reuniao-no-g7-e-aposta-para-reduzir-ameaca-comercial-arma-antiga-do-presidente-dos-eua.ghtml', 'G1 Economia', '2026-06-17T08:00:09', 8, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (39, 'Concurso do IBGE: veja cargos, salários e como se inscrever para mais de 8 mil vagas', 'Agentes do IBGE Reprodução O Instituto Brasileiro de Geografia e Estatística (IBGE) está com inscrições abertas para um novo processo seletivo simplificado voltado à realização do 12º Censo Agropecuário, Florestal e Aquícola. Ao todo, são oferecidas 8.238 vagas temporárias em cinco funções, com remunerações que variam entre R$ 2.128 e R$ 4.008, além de benefícios. As oportunidades estão distribuídas por todo o país e abrangem atividades administrativas, operacionais, de supervisão e suporte tecnológico ligadas à execução da pesquisa. As inscrições devem ser feitas exclusivamente pela internet,…', 'https://g1.globo.com/trabalho-e-carreira/concursos/noticia/2026/06/17/concurso-do-ibge-veja-cargos-salarios-e-como-se-inscrever-para-mais-de-8-mil-vagas.ghtml', 'G1 Economia', '2026-06-17T06:00:10', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (40, 'Ideia boa não basta: veja como testar um negócio antes de investir mais dinheiro', 'Ideia boa não basta: o que validar antes de investir Ter uma boa ideia não é garantia de sucesso no empreendedorismo. Segundo especialistas, muitos negócios começam no impulso e acabam enfrentando prejuízos por falta de planejamento, demanda insuficiente ou custos maiores do que o esperado. Antes de investir, o primeiro passo é entender se existe público interessado no produto ou serviço. Ouvir potenciais clientes e testar a ideia em pequena escala ajuda a identificar falhas e ajustar o negócio antes de um investimento maior. 🗒️ Tem alguma sugestão de reportagem? Mande para o g1 Uma das estrat…', 'https://g1.globo.com/empreendedorismo/guia-do-empreendedor/noticia/2026/06/17/ideia-boa-nao-basta-veja-como-testar-um-negocio-antes-de-investir-mais-dinheiro.ghtml', 'G1 Economia', '2026-06-17T05:00:12', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (41, 'Como investir se não sobra dinheiro? Especialistas dizem que esperar sobrar é um erro', 'Como investir se não sobra dinheiro? Esperar sobrar dinheiro para começar a investir pode ser um erro comum. A recomendação é inverter a lógica: em vez de guardar o que resta no fim do mês, separar uma parcela da renda logo após receber o salário. Uma das estratégias sugeridas é a chamada teoria dos três potes, que divide o orçamento entre gastos do dia a dia, reserva de segurança para emergências e investimentos voltados para objetivos futuros, como a compra da casa própria, viagens ou aposentadoria. A regra de bolso mais conhecida prevê a destinação de 60% da renda para despesas correntes, 3…', 'https://g1.globo.com/g1-explica/noticia/2026/06/17/como-investir-se-nao-sobra-dinheiro-especialistas-dizem-que-esperar-sobrar-e-um-erro.ghtml', 'G1 Economia', '2026-06-17T05:00:10', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (42, 'Acordo de paz entre EUA e Irã reforça expectativa de novo corte de juros pelo Banco Central nesta quarta', 'Adriano Machado/ Reuters A maior parte dos analistas do mercado financeiro já projetava, na semana passada, um novo corte de juros pelo Banco Central nesta quarta-feira (17) — quando se reúne o Comitê de Política Monetária (Copom). Após o anúncio do fechamento de um acordo de paz entre os Estados Unidos e o Irã, na noite deste domingo (14), a expectativa de uma nova redução da taxa básica da economia se consolidou. Atualmente, a taxa está em 14,5% ao ano. A maioria do mercado projeta um corte de 0,25 ponto percentual, para 14,25% ao ano. Se confirmada, será a terceira redução seguida no juro.…', 'https://g1.globo.com/economia/noticia/2026/06/17/acordo-de-paz-entre-eua-e-ira-reforca-expectativa-de-novo-corte-de-juros-pelo-banco-central-nesta-quarta.ghtml', 'G1 Economia', '2026-06-17T03:01:22', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (43, 'Prazo para pedir ressarcimento de descontos indevidos no INSS vai até 20 de junho; R$ 3,2 bilhões foram devolvidos', 'Prazo para pedido de ressarcimento de descontos do INSS termina dia 20 de junho Aposentados e pensionistas que tiveram descontos indevidos relacionados à fraude no Instituto Nacional do Seguro Social (INSS) têm até 20 de junho para contestar as cobranças. Até agora, mais de R$3,2 bilhões foram devolvidos a 4,7 milhões de segurados, segundo o INSS. O balanço é do dia 11 de junho. Após a aprovação da contestação, os segurados podem aderir ao acordo de ressarcimento e receber os valores corrigidos diretamente na conta em até três dias para receber administrativamente os valores descontados. Ao fe…', 'https://g1.globo.com/economia/noticia/2026/06/17/prazo-para-pedir-ressarcimento-de-de-descontos-indevidos-no-inss-vai-ate-20-de-junho-r32-bilhoes-foram-devolvidos.ghtml', 'G1 Economia', '2026-06-17T03:00:52', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (44, 'Bolsa Família 2026: pagamentos de junho começam nesta quarta; veja calendário', 'Bolsa Família veja as regras e dias de pagamentos em junho de 2026 A Caixa Econômica Federal inicia os pagamentos de junho do Bolsa Família 2026 nesta quarta-feira (17). Os primeiros a receber serão os beneficiários com Número de Identificação Social (NIS) com final 1. (veja mais abaixo o calendário completo) 📱Baixe o app do g1 para ver notícias em tempo real e de graça O dinheiro será disponibilizado nos últimos 10 dias úteis de cada mês, de forma escalonada. A exceção é o mês de dezembro, quando os pagamentos são antecipados. 🤔 Para saber a data correta de recebimento, a família deve verific…', 'https://g1.globo.com/economia/noticia/2026/06/17/bolsa-familia-2026-pagamentos-de-junho-comecam-nesta-quarta-veja-calendario.ghtml', 'G1 Economia', '2026-06-17T03:00:33', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (45, 'O que esperar da estreia de Kevin Warsh no Fed? Mercado observa tom do novo presidente', 'Trump indica Kevin Warsh para comandar o Federal Reserve, o banco central dos EUA A primeira reunião do Federal Reserve (Fed, o banco central dos Estados Unidos) sob o comando de Kevin Warsh termina nesta quarta-feira (17) em um cenário que costuma preocupar: inflação resistente, mercado de trabalho aquecido e pressão política por juros mais baixos. A expectativa de mercado financeiro é de que os juros sejam mantidos entre 3,5% e 3,75% ao ano. Ainda assim, o encontro é visto como o início de uma nova fase do BC americano. 🗒️Tem alguma sugestão de reportagem? Mande para o g1 Mais do que a decis…', 'https://g1.globo.com/economia/noticia/2026/06/17/o-que-esperar-da-estreia-de-kevin-warsh-no-fed-mercado-observa-tom-do-novo-presidente.ghtml', 'G1 Economia', '2026-06-17T03:00:31', 8, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (49, 'Senado Federal aprova projeto que blinda agências reguladoras contra bloqueios no orçamento', 'O Senado aprovou, por 51 votos a 17, nesta terça-feira (16), o projeto de lei complementar que altera a Lei de Responsabilidade Fiscal (LRF) que altera a Lei de Responsabilidade Fiscal (LRF) para blindar de contingenciamentos o orçamento das agências reguladoras. 🔎 Pelo novo arcabouço fiscal, o governo federal precisa perseguir uma meta de resultado primário definida anualmente na Lei de Diretrizes Orçamentárias (LDO). Para 2026, o objetivo é um superávit primário de 0,25% do PIB, mantendo a banda de tolerância de 0,25 ponto percentual para mais ou para menos. A proposta segue para análise da…', 'https://g1.globo.com/economia/noticia/2026/06/16/senado-federal-aprova-projeto-que-blinda-agencias-reguladoras-contra-bloqueios-no-orcamento.ghtml', 'G1 Economia', '2026-06-16T22:38:11', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (50, 'Privatização da Copasa é concluída em cerimônia na B3', 'Privatização da Copasa é concluída O processo de privatização da Companhia de Saneamento de Minas Gerais (Copasa) foi concluído nesta terça-feira (16), durante uma cerimônia na bolsa de valores brasileira, a B3, em São Paulo. A solenidade marcou a entrega das ações aos compradores e o pagamento ao estado. Ao todo, 171.113.881 papéis da estatal foram vendidos ao custo de R$ 49,03 cada, o que significa que R$ 8,38 bilhões serão depositados nos cofres de MG. ✅ Clique aqui para seguir o canal do g1 Minas no WhatsApp A Equatorial, selecionada como investidor de referência, passou a ser a maior acio…', 'https://g1.globo.com/mg/minas-gerais/noticia/2026/06/16/privatizacao-da-copasa-e-concluida-em-cerimonia-na-b3.ghtml', 'G1 Economia', '2026-06-16T18:56:23', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (51, 'Dona do Snapchat lança óculos de realidade aumentada de R$ 11 mil', 'Specs, óculos de realidade aumentada da Snap Divulgação/Snap A Snap, dona do Snapchat, lançou nesta terça-feira (16) seus óculos de realidade aumentada capazes de exibir, através das lentes, informações como mapas, vídeos, legendas de tradução, entre outros. Batizados de Specs, os dispositivos serão vendido por US$ 2.195 (R$ 11 mil, na conversão direta). Eles estão disponíveis em pré-venda e começarão a ser entregues até dezembro, primeiro para clientes nos Estados Unidos, no Reino Unido e na França. Com acabamento na cor preta, os Specs tem uma armação grossa e não precisam de bateria externa…', 'https://g1.globo.com/tecnologia/noticia/2026/06/16/dona-do-snapchat-lanca-oculos-de-realidade-aumentada-de-r-11-mil.ghtml', 'G1 Economia', '2026-06-16T18:53:36', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (54, 'É #FAKE que 232 empresas ''fugiram'' do Brasil para o Paraguai durante gestão de Haddad no Ministério da Fazenda', 'Mais de 230 empresas brasileiras chegaram ao Paraguai desde a promulgação da Lei Maquila, de 2007 g1 Circulam nas redes sociais publicações dizendo que mais de 232 empresas "fugiram" do Brasil para o Paraguai durante o atual governo Lula (PT), iniciado em 2023. É #FAKE. Selo Fake (Horizontal) g1 🔴 Como são os posts? Desde 25 de maio, publicações no X e no Instagram exibem fotos do ex-ministro da Fazenda Fernando Haddad (PT) e uma caixa de texto sobreposta à imagem que diz: "Mais de 232 empresas já fugiram para o Paraguai, expondo o desastre tributário brasileiro". Em um dos conteúdos com as me…', 'https://g1.globo.com/fato-ou-fake/noticia/2026/06/16/e-fake-que-232-empresas-fugiram-do-brasil-para-o-paraguai-durante-gestao-de-haddad-no-ministerio-da-fazenda.ghtml', 'G1 Economia', '2026-06-16T18:20:15', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (55, 'Lula discute veto à carne brasileira com líder da União Europeia e presidente da Comissão Europeia', 'Lula com com líder da União Europeia e presidente da Comissão Europeia. Ricardo Stuckert/ Presidência da República O presidente Luiz Inácio Lula da Silva (PT) se encontrou com a presidente da Comissão Europeia, Ursula von der Leyen, nesta terça-feira (16) na cúpula do G7, na França. Também participou da reunião bilateral o presidente do Conselho Europeu, António Costa. Eles discutiram sobre a decisão da UE de vetar a exportação da carne brasileira a partir de setembro. Segundo nota publicada pelo Palácio do Planalto, durante a reunião, os três "definiram um mecanismo bilateral entre o Itamarat…', 'https://g1.globo.com/politica/noticia/2026/06/16/lula-discute-veto-a-carne-brasileira-com-lider-da-uniao-europeia-e-presidente-da-comissao-europeia.ghtml', 'G1 Economia', '2026-06-16T18:20:00', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (56, 'Por que reabrir do Estreito de Ormuz é mais complexo do que liberar rodovia', 'Navios são vistos no Estreito de Ormuz, em Musandam, em Omã, no dia 16 de junho de 2026 Reuters Apesar da expectativa positiva dos mercados financeiros, a presença de minas navais e a própria fragilidade do acordo entre EUA e Irã indicam que situação deve demorar para retornar ao normal. Estados Unidos e Irã anunciaram neste domingo (14) um acordo preliminar para encerrar a guerra entre os dois países. O primeiro ponto destacado pelo presidente dos Estados Unidos, Donald Trump, foi a reabertura do Estreito de Ormuz, por onde passa um quinto do suprimento mundial de petróleo. 🗒️Tem alguma suges…', 'https://g1.globo.com/economia/noticia/2026/06/16/por-que-reabrir-do-estreito-de-ormuz-e-mais-complexo-do-que-liberar-rodovia.ghtml', 'G1 Economia', '2026-06-16T17:00:22', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (57, 'Comissão do Senado aprova projeto que blinda agências reguladoras contra bloqueios no orçamento', 'Comissão do Senado aprova projeto que blinda agências reguladoras contra bloqueios no orçamento Edilson Rodrigues/Agência Senado A Comissão de Infraestrutura (CI) do Senado aprovou nesta terça-feira (16) o projeto de lei complementar que altera a Lei de Responsabilidade Fiscal (LRF) para blindar de contingenciamentos o orçamento das agências reguladoras. Os parlamentares aprovaram um requerimento de urgência para que a proposta siga direto para o plenário. Antes, a proposta teria de passar também pela Comissão de Assuntos Econômicos (CAE). Com essa blindagem, as despesas das agências regulador…', 'https://g1.globo.com/economia/noticia/2026/06/16/comissao-do-senado-aprova-projeto-que-blinda-agencias-reguladoras-contra-bloqueios-no-orcamento.ghtml', 'G1 Economia', '2026-06-16T16:35:08', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (59, 'Desenrola 2.0: trabalhadores já solicitaram R$ 3,88 bilhões do FGTS para abatimento de dívidas', 'Cerca de 3,3 milhões de trabalhadores já autorizaram as instituições financeiras a consultar seu saldo no Fundo de Garantia por Tempo de Serviço (FGTS) para o abatimento de R$ 3,88 bilhões em dívidas dentro do Desenrola 2.0 — programa para reduzir o endividamento da população brasileira. Autorizar a instituição financeira a consultar o saldo não significa, necessariamente, que será feita a negociação com uso do FGTS. Dos trabalhadores que fizeram o pedido, 94,3% são optantes do saque-aniversário, sendo que 86,9% tem antecipações de recursos ativas. Esses pedidos ainda estão sendo avaliados pel…', 'https://g1.globo.com/economia/noticia/2026/06/16/desenrola-20-trabalhadores-ja-pediram-uso-de-r-388-bilhoes-do-fgts-para-abatimento-de-dividas.ghtml', 'G1 Economia', '2026-06-16T14:36:47', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (60, 'Com acordo entre EUA e Irã, governo vai suspender subsídios aos combustíveis, diz ministro', 'O ministro da Secretaria de Relações Institucionais, José Guimarães, afirmou nesta terça-feira (16) que o governo pretende suspender os subsídios aos combustíveis caso seja confirmado o acordo de paz entre Estados Unidos e Irã, previsto para ser assinado na sexta-feira (19), segundo anúncios feitos por líderes dos dois países. Em entrevista à GloboNews, Guimarães afirmou que a redução das tensões no Oriente Médio deve aliviar a pressão sobre os preços internacionais do petróleo, tornando desnecessária a manutenção das medidas adotadas pelo governo para conter o impacto dos combustíveis sobre o…', 'https://g1.globo.com/politica/noticia/2026/06/16/com-acordo-entre-eua-e-ira-governo-vai-suspender-subsidios-aos-combustiveis-diz-ministro.ghtml', 'G1 Economia', '2026-06-16T14:20:16', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (61, 'Pizza Hut será vendida por US$ 2,7 bilhões após anos de queda nas vendas e fechamento de lojas', 'Foto de 15 de dezembro de 2016 de um restaurante da Pizza Hut, em Nova Orleans, EUA. AP Photo/Gerald Herbert A controladora Yum Brands anunciou nesta terça-feira (16) a venda da rede de pizzarias Pizza Hut por US$ 2,7 bilhões. A gestora de investimentos LongRange Capital comprará a operação da rede fora da China, por cerca de US$ 1,5 bilhão, enquanto a Yum China Holdings ficará com os negócios no país asiático por aproximadamente US$ 1,2 bilhão. 🗒️Tem alguma sugestão de reportagem? Envie para o g1 A Pizza Hut enfrenta dificuldades há anos. Em fevereiro, a Yum Brands informou que estudava vende…', 'https://g1.globo.com/economia/noticia/2026/06/16/pizza-hut-sera-vendida-por-us-27-bilhoes.ghtml', 'G1 Economia', '2026-06-16T14:13:02', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (64, 'Trump diz que ''em breve'' pode voltar a impor sanções ao petróleo da Rússia', 'Oleoduto de Druzhba, que passa pela Ucrânia e leva petróleo russo para países da Europa. Foto de 2022. REUTERS/Bernadett Szabo/Foto de Arquivo O presidente americano Donald Trump disse nessa terça-feira (16) que "em breve" os EUA poderão voltar a impor sanções ao petróleo da Rússia. A declaração foi feita a jornalistas, durante uma reunião com o presidente dos Emirados Árabes Unidos, o xeique Mohammed bin Zayed Al Nahyan, na cúpula do G7, na França. Trump afirmou que os Estados Unidos podem, agora, deixar expirar as isenções relacionadas ao petróleo russo, após fecharem um acordo para encerrar…', 'https://g1.globo.com/economia/noticia/2026/06/16/trump-diz-que-em-breve-pode-voltar-a-impor-sancoes-ao-petroleo-da-russia.ghtml', 'G1 Economia', '2026-06-16T12:52:37', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (66, 'Dólar fecha em alta com petróleo no radar e à espera dos juros; Ibovespa cai', 'Entenda o que faz o preço do dólar subir ou cair O dólar fechou em alta nesta terça-feira (16), com avanço de 0,39%, cotado a R$ 5,0862. Já o Ibovespa, principal índice da bolsa brasileira, encerrou o dia em queda de 0,45%, aos 169.648 pontos. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 ▶️ O novo acordo de paz entre os Estados Unidos e o Irã continua a gerar expectativa nos mercados financeiros. O entendimento incluiria, entre outros pontos, a reabertura do Estreito de Ormuz e uma nova trégua, incluindo o Líbano. Segundo o presidente americano, Donald Trump, o tratado também deixa "b…', 'https://g1.globo.com/economia/noticia/2026/06/16/dolar-ibovespa.ghtml', 'G1 Economia', '2026-06-16T12:00:08', 9, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (68, 'Os desafios de Lula no G7 para não ficar escanteado em meio ao foco em crises globais e embate entre Trump e Europa', 'Lula fez sua primeira reunião bilateral às margens do G7 com Emmanuel Macron, presidente da França e anfitrião do evento Ricardo Stuckert / PR O presidente Luiz Inácio Lula da Silva (PT) inicia nesta terça-feira (16/06) sua participação oficial no G7 – o fórum que reúne sete das maiores economias industrializadas do planeta. Lula foi convidado para o evento, que acontece em Évian-les-Bains, na França, pelo presidente francês, Emmanuel Macron. É costume que o anfitrião do fórum escolha alguns países não membros do G7 para acompanhar as discussões ampliadas, a partir do segundo dia de reuniões.…', 'https://g1.globo.com/politica/noticia/2026/06/16/os-desafios-de-lula-no-g7-para-nao-ficar-escanteado-em-meio-ao-foco-em-crises-globais-e-embate-entre-trump-e-europa.ghtml', 'G1 Economia', '2026-06-16T08:29:18', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (69, 'Leilões de propriedades rurais disparam no Brasil com aumento da inadimplência no campo', 'Colheita de soja no Rio Grande do Sul. Reuters Os leilões de propriedades rurais retomadas por credores estão crescendo rapidamente em todo o Brasil, segundo dados compilados para a Reuters, à medida que a inadimplência no campo chegou a quase um quinto dos empréstimos em circulação. A queda nos preços dos grãos, os juros elevados e o aumento dos custos dos insumos, somados aos impactos de um clima cada vez mais imprevisível, têm levado a falências e à perda de propriedades rurais no país, disseram produtores e analistas à Reuters. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 Para agr…', 'https://g1.globo.com/economia/agronegocios/noticia/2026/06/16/leiloes-de-propriedades-rurais-disparam-no-brasil-com-aumento-da-inadimplencia-no-campo.ghtml', 'G1 Economia', '2026-06-16T08:03:31', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (70, 'Único brasileiro inscrito em audiência sobre tarifaço defende PIX e cobra debate técnico: ''Temos que sair da retórica''', 'Gustavo Pessoa, professor de Economia da Fundação Getulio Vargas (FGV) e pesquisador de riscos no sistema financeiro Arquivo pessoal Até agora, somente um brasileiro se inscreveu para participar da audiência pública que pode influenciar os próximos rumos da disputa comercial entre Brasil e Estados Unidos. Gustavo Pessoa é professor de Economia da Fundação Getulio Vargas (FGV) e pesquisador de riscos no sistema financeiro. A audiência está prevista para 6 de julho e antecede a decisão final do governo dos EUA sobre possíveis medidas comerciais. Empresas, associações, governos e outros interessa…', 'https://g1.globo.com/economia/noticia/2026/06/16/unico-brasileiro-inscrito-em-audiencia-sobre-tarifaco-cobra-debate-tecnico.ghtml', 'G1 Economia', '2026-06-16T08:00:11', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (71, 'A ''guerra silenciosa'' entre China e Panamá por controle de portos no Canal', 'A ''guerra silenciosa'' entre China e Panamá por controle de portos no Canal Getty Images via BBC A história da empresa CK Hutchison Holdings e do Panamá se transformou em um dos maiores conflitos geopolíticos ligados ao Canal do Panamá nos últimos anos. O embate envolve duas superpotências, Estados Unidos e China, uma hidrovia por onde passa até 6% do comércio mundial e alguns dos mais importantes operadores portuários do planeta. E a exclusão dessa empresa chinesa sediada em Hong Kong da administração de dois portos provocou o que parece ser uma dura punição por parte de Pequim, em meio à cres…', 'https://g1.globo.com/mundo/noticia/2026/06/16/a-guerra-silenciosa-entre-china-e-panama-por-controle-de-portos-no-canal.ghtml', 'G1 Economia', '2026-06-16T07:01:41', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (73, 'Agentes no OnlyFans controlam e ameaçam modelos enquanto retêm metade dos ganhos, revela BBC', 'Rebecca, criadora de conteúdo no OnlyFans, foi alvo de mensagens abusivas e violência Gus Palmer/BBC Aviso: esta reportagem contém relatos de violência que podem ser perturbadores para alguns leitores Rebecca, criadora de conteúdo na plataforma OnlyFans, afirma que entrou para uma agência depois que lhe prometeram ajudar a aumentar seus ganhos na rede social voltada para conteúdo adulto. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 Em vez disso, segundo ela, foi vítima de abusos, recebeu ameaças contra a filha e teve homens mascarados enviados à sua casa para agredi-la. "Eles eram ado…', 'https://g1.globo.com/tecnologia/noticia/2026/06/16/agentes-no-onlyfans-controlam-e-ameacam-modelos-enquanto-retem-metade-dos-ganhos-revela-bbc.ghtml', 'G1 Economia', '2026-06-16T06:00:21', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (74, '''Taxa das blusinhas'': governo volta a tributar compras internacionais de baixo valor em 2027, mas com imposto e alíquota diferentes', 'Importados de até US$ 50 voltam a pagar imposto em 2027 A taxação de encomendas com valor abaixo de US$ 50, zerada neste ano com o fim da "taxa das blusinhas", retornará em 2027 por meio da Contribuição sobre Bens e Serviços (CBS) — tributo federal criado no âmbito da reforma tributária sobre o consumo. 🔎A CBS substituirá o antigo imposto de importação, que tinha alíquota de 20% para encomendas internacionais de baixo valor. A alíquota a ser cobrada, entretanto, ainda não está definida. O valor da CBS, que está sendo calculado pela Receita Federal em parceria com o Tribunal de Contas da União…', 'https://g1.globo.com/economia/noticia/2026/06/16/taxa-das-blusinhas-governo-volta-a-tributar-compras-internacionais-de-baixo-valor-em-2027-mas-com-imposto-e-aliquota-diferentes.ghtml', 'G1 Economia', '2026-06-16T06:00:09', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (76, 'Nova taxação proposta pelos EUA pode impactar um terço das exportações brasileiras com tarifas de até 37,5%, projeta CNI', 'Projeção da Confederação Nacional da Indústria (CNI) indica que, caso as novas tarifas propostas pelo Representante Comercial dos Estados Unidos (USTR, na sigla em inglês) entrem em vigor, 31,6% das exportações brasileiras para os EUA passarão a ser taxadas em 37,5%, ante os atuais 10%. A mudança representa um aumento de 27,5 pontos percentuais. Outros 3,6% dos embarques brasileiros para o mercado norte-americano seriam submetidos a uma tarifa de 12,5%, frente aos 10% cobrados atualmente, uma elevação de 2,5 pontos percentuais. Isso porque, no início deste mês, os Estados Unidos concluíram uma…', 'https://g1.globo.com/economia/noticia/2026/06/15/nova-taxacao-proposta-pelos-eua-pode-impactar-um-terco-das-exportacoes-brasileiras-com-tarifas-de-ate-375percent-projeta-cni.ghtml', 'G1 Economia', '2026-06-15T19:49:47', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (77, 'Flórida acusa TikTok de violar lei que proíbe menores de 14 anos em redes sociais', 'TikTok REUTERS O estado americano da Flórida abriu nesta segunda-feira (15) um processo contra o TikTok, alegando que a empresa viola uma lei estadual ao deixar menores de 14 anos criarem contas na plataforma. A ação também acusa o TikTok de deturpar dados sobre conteúdo violento ou sexual ao qual crianças têm acesso na rede social. O procurador-geral da Flórida, James Uthmeier, disse que o TikTok engana pais de crianças de forma consciente. "Temos tolerância zero para empresas que priorizam o lucro em detrimento da segurança das crianças", afirmou. A lei da Flórida, conhecida como H.B. 3, exi…', 'https://g1.globo.com/tecnologia/noticia/2026/06/15/florida-processo-tiktok.ghtml', 'G1 Economia', '2026-06-15T19:23:43', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (79, 'Contrabando, espionagem, sabotagem: como a Rússia usa ''frota fantasma'' para contornar sanções do Ocidente', 'O navio de patrulha HSwMS Carlskrona acompanha um navio cargueiro perto do litoral da Suécia, como parte da missão da Otan Sentinela do Báltico AFP via BBC O Kremlin afirma que a Rússia está "imune" às sanções impostas pelo presidente americano, Donald Trump, a duas das suas maiores companhias de petróleo. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 O que mantém as exportações russas de petróleo por via marítima é uma "frota fantasma": navios petroleiros "zumbis" transportam milhões de barris de petróleo para compradores em busca de barganhas de todo o mundo, evitando as sanções. A f…', 'https://g1.globo.com/economia/noticia/2026/06/15/contrabando-espionagem-sabotagem-como-a-russia-usa-frota-fantasma-para-contornar-sancoes-do-ocidente.ghtml', 'G1 Economia', '2026-06-15T16:15:13', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (81, 'Ministro da Fazenda defende revisão do cálculo da inflação no Brasil', 'Secretário executivo da Fazenda, Dario Durigan. Diogo Zacarias/Ministério da Fazenda O ministro da Fazenda, Dario Durigan, se mostrou favorável a discutir possíveis ajustes na forma como a inflação é calculada no Brasil, argumentando que estudiosos apontam uma defasagem na lista de itens usados para medis a alta de preços. Em podcast produzido pela Warren Investimentos, Durigan afirmou que o modelo atual ainda dá mais importância a itens que perderam relevância, enquanto outros, que ganharam peso nos últimos anos, têm menor representação. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 "…', 'https://g1.globo.com/economia/noticia/2026/06/15/ministro-da-fazenda-calculo-da-inflacao-no-brasil.ghtml', 'G1 Economia', '2026-06-15T14:58:50', 7, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (83, 'Grande fã de Musk, bilionário Ron Baron compra US$ 1 bilhão de ações em IPO da SpaceX; saiba quem é', 'Uma transmissão ao vivo mostra o CEO da SpaceX, Elon Musk, no dia da oferta pública inicial (IPO) da SpaceX no Nasdaq MarketSite, na cidade de Nova York, EUA, 12 de junho de 2026. REUTERS/Jeenah Moon O fundador, presidente e gestor de portfólio da Baron Capital, Ron Baron, afirmou nesta segunda-feira (15) que comprou US$ 1 bilhão (R$ 5,1 bilhões) em ações da SpaceX na oferta pública inicial (IPO, na sigla em inglês) da companhia, na sexta-feira (12) da semana passada. Com isso, o bilionário elevou sua participação na empresa para US$ 25 bilhões (R$ 127,1 bilhões), considerando todos os fundos…', 'https://g1.globo.com/tecnologia/noticia/2026/06/15/ron-baron-spacex.ghtml', 'G1 Economia', '2026-06-15T14:27:21', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (84, 'Com ''gatilho'' na regra fiscal, servidor público não terá reajuste acima da inflação em 2027, diz ministro da Fazenda', 'O ministro da Fazenda, Dario Durigan, afirmou nesta segunda-feira (15) que o governo não poderá conceder reajuste aos servidores públicos acima da inflação em 2027 por conta de um "gatilho" existente na regra das contas públicas. A declaração foi dada durante participação no podcast Warren Política, conduzido pelo economista Felipe Salto. "Temos o novo marco fiscal, criamos um gatilho adicional. Ano que vem não vamos ter ganho real ao servidor público, o que é um ganho [em termos de contenção de despesas] em um primeiro ano de governo", disse o ministro da Fazenda, Dario Durigan. Agora no g1 E…', 'https://g1.globo.com/economia/noticia/2026/06/15/com-gatilho-na-regra-fiscal-servidor-publico-nao-tera-reajuste-acima-da-inflacao-em-2027-diz-ministro-da-fazenda.ghtml', 'G1 Economia', '2026-06-15T13:52:01', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (85, 'Justiça aprova pedido de recuperação judicial da dona da Tok&Stok e da Mobly', 'Mobly faz acordo para comprar controle da Tok&amp;Stok. Reprodução/ Mobly / Tok&amp;Stok O Grupo Toky, dono da Tok&amp;Stok e da Mobly, afirmou nesta segunda-feira (15) que a Justiça aprovou o pedido de recuperação judicial da companhia e de suas subsidiárias. 🔎 Recuperação judicial é um processo em que uma empresa com dificuldades financeiras pede proteção à Justiça para renegociar dívidas e evitar a falência, enquanto continua funcionando. A empresa entrou com o pedido de recuperação judicial em maio deste ano, na 3ª Vara de Falências e Recuperações Judiciais do Foro Central Cível de São Pau…', 'https://g1.globo.com/economia/noticia/2026/06/15/justica-aprova-pedido-de-recuperacao-judicial-da-dona-da-tokandstok-e-da-mobly.ghtml', 'G1 Economia', '2026-06-15T13:47:32', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (87, 'Fox compra Roku por US$ 22 bilhões', 'Fachada da Roku em um prédio no Texas, nos EUA. Mike Blake/Reuters A Fox Corporation anunciou nesta segunda-feira (15) que firmou um acordo para a compra da Roku, plataforma e sistema operacional de televisões, voltada a facilitar o acesso a serviços de streaming. A aquisição será feita por meio de uma combinação de dinheiro e ações ordinárias (com direito a voto), em um negócio de aproximadamente US$ 22 bilhões (R$ 111,8 bilhões). O preço pago por ação será de US$ 160 (R$ 813,23). 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 A transação combina o conteúdo de esportes, notícias e entr…', 'https://g1.globo.com/economia/noticia/2026/06/15/fox-roku.ghtml', 'G1 Economia', '2026-06-15T12:39:07', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (88, 'Dólar sobe e fecha em alta com sinalização de acordo EUA–Irã; Ibovespa cai', 'Entenda o que faz o preço do dólar subir ou cair O dólar fechou em alta nesta segunda-feira (15), com avanço de 0,09%, cotado a R$ 5,0666. Já o Ibovespa, principal índice da bolsa brasileira, encerrou o pregão em queda de 0,42%, aos 170.415 pontos. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 ▶️ O novo acordo de paz entre os Estados Unidos e o Irã traz alívio para os mercados financeiros nesta segunda-feira. A expectativa é que o memorando seja assinado na próxima sexta-feira (19), na Suíça. Nenhuma das duas partes informou o conteúdo do tratado, mas, segundo a imprensa americana, o e…', 'https://g1.globo.com/economia/noticia/2026/06/15/dolar-ibovespa.ghtml', 'G1 Economia', '2026-06-15T12:00:08', 8, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (89, 'Departamento de Justiça dos EUA aprova compra da Warner Bros pela Paramount', 'Foto ilustrativa mostra logotipos da Paramount e da Warner Bros Reuters O Departamento de Justiça dos Estados Unidos aprovou na sexta-feira (12) a aquisição da Warner Bros. Discovery pela Paramount Skydance em um negócio avaliado em US$ 110 bilhões, concluindo que a operação não representa risco à concorrência nos mercados de streaming, televisão ou cinema. A decisão dá mais um aval regulatório à fusão, embora o acordo ainda enfrente análises de outros órgãos e possíveis ações judiciais nos Estados Unidos e no exterior. Baixe o GloboPop para assistir a vídeos curtos verticais da Globo Em comun…', 'https://g1.globo.com/economia/noticia/2026/06/15/departamento-de-justica-dos-eua-aprova-compra-da-warner-bros-pela-paramount.ghtml', 'G1 Economia', '2026-06-15T11:54:04', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (90, 'Mercado financeiro sobe para 5,30% estimativa de inflação em 2026 e projeta corte menor de juros', 'O mercado financeiro elevou novamente sua estimativa média para a inflação em 2026, que avançou para 5,30%. Esta é décima quarta semana seguida de aumento. Os economistas também passaram a projetar um corte menor de juros neste e nos próximos anos (veja mais abaixo nessa reportagem). As expectativas fazem parte do "Boletim Focus", divulgado nesta segunda-feira (15) pelo Banco Central (BC), com base em pesquisa realizada na última semana com mais de 100 instituições financeiras. A explicação é que a guerra no Oriente Médio fez disparar o preço do petróleo e, por isso, tem potencial de pressiona…', 'https://g1.globo.com/economia/noticia/2026/06/15/mercado-financeiro-sobe-para-530percent-estimativa-de-inflacao-em-2026-e-projeta-corte-menor-de-juros.ghtml', 'G1 Economia', '2026-06-15T11:31:51', 7, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (91, 'Bolsas mundiais sobem e petróleo cai após anúncio de possível acordo entre EUA e Irã', 'Paquistão anuncia acordo de paz na guerra entre Estados Unidos e Irã As bolsas de valores ao redor do mundo subiram nesta segunda-feira (15) depois que Estados Unidos e Irã anunciaram um acordo preliminar para encerrar a guerra e reabrir o Estreito de Ormuz, uma das principais rotas de transporte de petróleo do mundo. A notícia reduziu a preocupação dos investidores e também provocou uma forte queda no preço do petróleo. Na Ásia, as bolsas fecharam em forte alta, e o clima de otimismo também impulsionou a abertura dos mercados na Europa. Veja como reagiram os principais mercados: 🛢️ Petróleo O…', 'https://g1.globo.com/economia/noticia/2026/06/15/bolsas-asiaticas-e-europeias-abrem-em-alta-apos-anuncio-de-possivel-acordo-entre-eua-e-ira.ghtml', 'G1 Economia', '2026-06-15T07:49:17', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (92, 'Nas vésperas do G7, Trump ameaça impor tarifa de 100% sobre vinhos franceses se país não eliminar imposto sobre big techs', 'Donadl Trump ao lado de Melania Trump no UFC Casa Branca Evan Vucci / Reuters O presidente dos Estados Unidos, Donald Trump, alertou que a França corre o risco de enfrentar uma nova guerra comercial com os americanos. Em entrevista exclusiva publicada pelo jornal The New York Post, o líder da Casa Branca declarou que, a menos que Paris elimine o imposto digital sobre as gigantes de tecnologia dos EUA, Washington "não terá outra escolha" a não ser impor tarifas de 100% sobre os vinhos franceses. Segundo a matéria, Trump fez o alerta de forma direta ao presidente francês Emmanuel Macron. O ameri…', 'https://g1.globo.com/economia/noticia/2026/06/15/trump-ameaca-impor-tarifa-de-100percent-sobre-vinhos-franceses-se-pais-nao-eliminar-imposto-sobre-big-techs.ghtml', 'G1 Economia', '2026-06-15T05:51:52', 4, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (94, 'O que é o Estreito de Ormuz, fundamental para petróleo mundial; Irã pode reabrir passagem após acordo com EUA', 'Os Estados Unidos e o Irã acertaram no domingo (14) um acordo de paz para encerrar o conflito de quase quatro meses entre os dois países —a assinatura está prevista para sexta-feira (19). Segundo o Irã, o Estreito de Ormuz pode ser aberto dentro de 30 dias. O Estreito de Ormuz uma "artéria" da indústria petrolífera por onde passa cerca de 20% de todo o petróleo do mundo. Seu fechamento durante período de conflito teve forte impacto na economia global. O anúncio do acordo de paz, aliás, derrubou os preços do petróleo na abertura do pregão de segunda-feira. Veja abaixo outros detalhes sobre o es…', 'https://g1.globo.com/economia/noticia/2026/06/15/o-que-e-o-estreito-de-ormuz-fundamental-para-petroleo-mundial-ira-pode-reabrir-passagem-apos-acordo-com-eua.ghtml', 'G1 Economia', '2026-06-15T03:00:33', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (100, 'Rota de colisão: por que o G7 teme que os desequilíbrios da economia global acabem em crise', 'Países do G7 pedem desescalada do conflito entre Israel e Irã REUTERS/Suzanne Plunkett/Pool O aumento das exportações da China, a deterioração das contas dos Estados Unidos e o baixo nível de investimentos na Europa têm preocupado o G7, grupo que reúne as sete maiores economias desenvolvidas do mundo. O temor é que esse cenário aumente as tensões comerciais e deixe a economia global mais vulnerável a crises financeiras. O assunto tem sido uma das prioridades da França, que atualmente ocupa a presidência do grupo. Segundo o presidente francês, Emmanuel Macron, os desequilíbrios entre o comércio…', 'https://g1.globo.com/economia/noticia/2026/06/14/por-que-o-g7-teme-que-os-desequilibrios-da-economia-global-acabem-em-crise.ghtml', 'G1 Economia', '2026-06-14T07:01:38', 7, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (102, 'Claude x ChatGPT: qual empresa sairá na frente na corrida trilionária da IA?', 'Sam Altman e Dario Amodei: qual CEO sairá na frente na corrida de Wall Street? Jens Schicke/IMAGO/Julien De Rosa/AFP via DW Poderia ser um roteiro de Hollywood, mas é real. Dois nerds ambiciosos que, com estratégias duras e muita persistência, disputam a supremacia na Inteligência Artificial (IA). Também não faltam reviravoltas. Dario Amodei, chefe da Anthropic, criadora do Claude, recentemente pediu uma pausa no desenvolvimento da IA, alertando que os humanos poderiam perder o controle. Baixe o GloboPop para assistir a vídeos curtos verticais da Globo E isso poucos dias após apresentar à auto…', 'https://g1.globo.com/tecnologia/noticia/2026/06/14/claude-x-chatgpt-qual-empresa-saira-na-frente-na-corrida-trilionaria-da-ia.ghtml', 'G1 Economia', '2026-06-14T07:01:10', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (103, 'Quem cuida do gramado? Conheça a cadeia que abastece campos de futebol no Brasil', 'Produção de gramado para estádios envolve máquinas e agrônomos especializados Quando a bola começa a rolar no campo, os holofotes se voltam para os craques. Mas existe outro time, longe das câmeras, responsável por garantir que o espetáculo aconteça sem tropeços: o dos agrônomos e produtores rurais que trabalham para manter os gramados em condições ideais. O cultivo da grama, conhecido como gramicultura, é relativamente recente no país e se desenvolveu principalmente nos últimos 20 anos, conta o agrônomo Rafael Froes, responsável por uma fazenda em São José dos Campos (SP). No local, um dos es…', 'https://g1.globo.com/economia/agronegocios/globo-rural/noticia/2026/06/14/quem-cuida-do-gramado-conheca-a-cadeia-que-abastece-campos-de-futebol-no-brasil.ghtml', 'G1 Economia', '2026-06-14T06:00:34', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (105, 'Nubank diz que ''desenvolvedor acionou por engano'' comando que enviou mensagem sobre liquidação extrajudicial', 'Logo do Nubank na Bolsa de Valores de Nova York. Brendan McDermid/ Reuters O Nubank explicou, em comunicado enviado à imprensa neste sábado (13), os motivos que levaram ao envio, por engano, de uma mensagem anunciando a liquidação extrajudicial da instituição financeira. De acordo como o comunicado, o "episódio foi resultado de um erro técnico pontual, identificado e corrigido rapidamente". "Foi identificado que um desenvolvedor acionou por engano um fluxo de comunicação relacionado à liquidação de instituições financeiras. Na ausência de uma instituição real vinculada a esse fluxo, o nome da…', 'https://g1.globo.com/economia/noticia/2026/06/13/nubank-diz-que-mensagem-sobre-liquidacao-extrajudicial-enviada-a-clientes-foi-erro-tecnico-pontual.ghtml', 'G1 Economia', '2026-06-14T00:32:48', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (108, 'Antes de ser revogada, ''taxa das blusinhas'' rendeu mais de R$ 2 bilhões ao governo em 2026', 'Imposto de importação federal sobre encomendas foi revogado em meados de maio Jornal Nacional O governo arrecadou R$ 2,13 bilhões em imposto de importação de janeiro até meados de maio com as encomendas internacionais, segundo a Secretaria da Receita Federal. O valor ingressou nos cofres públicos no decorrer deste ano, antes de chamada "taxa das blusinhas" ser revogada em meio à corrida eleitoral. Na comparação com os cinco primeiros meses do ano passado, com mais dias (pois considera maio de 2025 inteiro), houve uma alta de 15,4%. Naquele período, foram arrecadados R$ 1,84 bilhão com o impost…', 'https://g1.globo.com/economia/noticia/2026/06/13/antes-de-ser-revogada-taxa-das-blusinhas-rendeu-mais-de-r-2-bilhoes-ao-governo-em-2026.ghtml', 'G1 Economia', '2026-06-13T14:25:18', 3, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (110, 'IPO da SpaceX coloca o mercado financeiro no centro da disputa tecnológica entre EUA e China', 'SpaceX leva à bolsa de valores uma aposta que vai além dos foguetes A corrida espacial do século XXI não coloca Estados Unidos e China em lados opostos apenas na Lua. Ela também opõe dois modelos distintos de financiamento para tecnologias consideradas estratégicas no tabuleiro geopolítico. De um lado, Pequim avança por meio de empresas estatais, planejamento de longo prazo e recursos públicos. Do outro, a SpaceX conseguiu US$ 75 bilhões (R$ 382,6 bilhões) diretamente em Wall Street para financiar projetos que vão de redes globais de comunicação à inteligência artificial e à infraestrutura orb…', 'https://g1.globo.com/economia/noticia/2026/06/13/ipo-da-spacex-coloca-o-mercado-financeiro-no-centro-da-disputa-tecnologica-entre-eua-e-china.ghtml', 'G1 Economia', '2026-06-13T08:00:45', 9, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (112, 'Como lidar com a frustração profissional: o que atletas fora da Copa ensinam sobre decepção', 'Como lidar com a frustração profissional: o que atletas fora da Copa ensinam sobre o tema Horas antes da convocação oficial da seleção brasileira para a Copa do Mundo de 2026, o goleiro Hugo Souza apareceu diante da câmera do próprio canal no YouTube tentando controlar a ansiedade. Cercado de amigos e familiares, acompanhava ao vivo a lista anunciada por Carlo Ancelotti. Nos últimos meses, Hugo vinha sendo chamado com frequência pelo treinador italiano e atravessava uma das fases mais consistentes de sua carreira. Então, os nomes começaram a ser anunciados: Alisson, Ederson e Weverton. E não o…', 'https://g1.globo.com/trabalho-e-carreira/noticia/2026/06/13/como-lidar-com-a-frustracao-profissional-o-que-atletas-fora-da-copa-ensinam-sobre-decepcao.ghtml', 'G1 Economia', '2026-06-13T06:00:20', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (115, 'MrBeast bate recorde e supera 500 milhões de inscritos; conheça o maior youtuber do planeta', 'Jimmy Donaldson, conhecido como MrBeast Richard Shotwell/Invision/AP MrBeast, maior youtuber do mundo, alcançou um marco inédito nesta sexta-feira (12) ao se tornar o primeiro criador de conteúdo individual a ultrapassar a marca de 500 milhões de inscritos na plataforma. A informação foi celebrada pelo próprio Youtube em seu site oficial. Quem é MrBeast Jimmy Donaldson, conhecido como MrBeast, se tornou famoso por produzir vídeos com desafios que envolvem grandes quantias de dinheiro e por investir valores milionários em suas gravações, que frequentemente misturam entretenimento e ações de imp…', 'https://g1.globo.com/tecnologia/noticia/2026/06/12/mrbeast-bate-recorde-e-supera-500-milhoes-de-inscritos-conheca-o-maior-youtuber-do-planeta.ghtml', 'G1 Economia', '2026-06-12T18:00:10', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (116, 'Ações da SpaceX disparam quase 20% em estreia na Nasdaq', 'SpaceX abre capital e Musk fica trilionário O IPO da SpaceX surpreendeu até os investidores mais otimistas. Segundo a Bloomberg, investidores de varejo — pessoas físicas — enviaram mais de US$ 70 bilhões em pedidos para participar da oferta. Com a demanda acima do esperado, as ações da SpaceX subiam quase 30% em sua estreia na Nasdaq nesta sexta-feira (12) e eram negociadas a US$ 173,65 (R$ 893,92) por volta das 14h50. Na esteira, Elon Musk se tornou o primeiro trilionário da história. No fechamento do dia, a alta perdeu força e encerrou em 19,2%. A empresa de Elon Musk chegou à bolsa após pre…', 'https://g1.globo.com/economia/noticia/2026/06/12/acoes-da-spacex-estreia.ghtml', 'G1 Economia', '2026-06-12T17:49:37', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (117, 'O que é liquidação extrajudicial, termo usado em e-mail enviado por engano pelo Nubank', 'Logo do Nubank na Bolsa de Valores de Nova York. Brendan McDermid/ Reuters Alguns clientes do Nubank receberam, nesta sexta-feira (12), e-mails informando sobre uma suposta liquidação extrajudicial da instituição pelo Banco Central (BC). Uma liquidação extrajudicial é uma medida aplicada a instituições financeiras em situação de insolvência ou com graves problemas financeiros. O objetivo é encerrar as atividades da empresa de forma organizada, preservar o patrimônio disponível e garantir o pagamento dos credores. LEIA TAMBÉM: Nubank envia e-mail por engano sobre suposta liquidação do banco; in…', 'https://g1.globo.com/economia/noticia/2026/06/12/o-que-e-liquidacao-extrajudicial-termo-usado-em-e-mail-enviado-por-engano-pelo-nubank.ghtml', 'G1 Economia', '2026-06-12T16:22:50', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (118, 'Elon Musk vira o primeiro trilionário da história da humanidade', 'Elon Musk vira o primeiro trilionário da história da humanidade Elon Musk se tornou nesta sexta-feira (12) o primeiro trilionário da história após a estreia da SpaceX na Nasdaq, principal bolsa de tecnologia dos Estados Unidos, que reúne empresas como Apple, Google e Microsoft. Vale destacar que, antes mesmo de se tornar um trilionário, Musk já liderava a lista da revista Forbes de pessoa mais rica do mundo. (conheça a trajetória dele). Após a estreia da SpaceX na bolsa, a Forbes passou a classificar Elon Musk como o primeiro trilionário da Terra e estimou sua fortuna em US$ 1,1 trilhão na man…', 'https://g1.globo.com/tecnologia/noticia/2026/06/12/quem-e-elon-musk.ghtml', 'G1 Economia', '2026-06-12T16:02:55', 6, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (120, 'Nubank envia e-mail por engano sobre suposta liquidação do banco; instituição segue operando', 'Logotipo de Nubank na sede do banco em São Paulo, Brasil, 19 de junho de 2018 Paulo Whitaker/Reuters Alguns clientes do Nubank receberam, nesta sexta-feira (12), e-mails informando sobre uma suposta liquidação extrajudicial da instituição pelo Banco Central (BC). As mensagens foram enviadas por engano, o banco não foi liquidado e segue operando normalmente. O g1 teve acesso a um dos e-mails enviados a partir de um domínio oficial da empresa. Na mensagem, o Nubank informava que o BC havia determinado a liquidação da instituição e que "o ativo deste emissor sairá de circulação definitivamente".…', 'https://g1.globo.com/economia/noticia/2026/06/12/nubank-aviso.ghtml', 'G1 Economia', '2026-06-12T15:41:53', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (121, 'Lula lança linha de crédito para compra de moto e bicicleta elétrica por entregadores de app; veja regras', 'Lula diz que motoristas de app estão deixando a ''invisibilidade'' O presidente Luiz Inácio Lula da Silva (PT) lançou nesta sexta-feira (12), no Palácio do Planalto, uma linha de crédito especial para a compra de motos e bicicletas elétricas por entregadores que trabalham por aplicativos. Entre os objetivos da linha de crédito, que estará disponível a partir de 13 de julho, estão a descarbonização e a renovação da frota de motos e bicicletas em circulação. Conforme o governo, poderão adquirir os veículos os motociclistas ou ciclistas que prestam serviços de transporte urbano individual de passag…', 'https://g1.globo.com/economia/noticia/2026/06/12/lula-lanca-linha-de-credito-para-compra-de-motos-por-entregadores-de-app-veja-regras.ghtml', 'G1 Economia', '2026-06-12T15:26:45', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (122, 'SpaceX ultrapassa avaliação de US$ 2 trilhões em estreia na Nasdaq', 'Uma transmissão ao vivo mostra o CEO da SpaceX, Elon Musk, no dia da oferta pública inicial (IPO) da SpaceX no Nasdaq MarketSite, na cidade de Nova York, EUA, 12 de junho de 2026. REUTERS/Jeenah Moon A SpaceX atingiu US$ 2,1 trilhões em valor de mercado em sua estreia na Nasdaq nesta sexta-feira (12). O movimento reflete o entusiasmo em torno da empresa liderada por Elon Musk e a coloca no caminho para se tornar a sexta maior companhia de capital aberto dos Estados Unidos. As ações tinham previsão de abrir em torno de US$ 175, cerca de 30% acima do preço de US$ 135 definido na oferta inicial (…', 'https://g1.globo.com/economia/noticia/2026/06/12/spacex-deve-ultrapassar-avaliacao-de-us-2-trilhoes-em-estreia-na-nasdaq.ghtml', 'G1 Economia', '2026-06-12T15:03:41', 8, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (123, 'SpaceX estreia na bolsa: veja como investir na empresa e em outras ações no exterior', 'As pessoas se reúnem para assistir a uma transmissão ao vivo com o CEO da SpaceX, Elon Musk, no dia da oferta pública inicial (IPO) da SpaceX no Nasdaq MarketSite, em Nova York REUTERS/Jeenah Moon A SpaceX, empresa de foguetes, satélites e inteligência artificial do bilionário Elon Musk, estreou na Nasdaq, bolsa de valores de tecnlogia de Wall Street, nesta sexta-feira (12). Avaliada em cerca de US$ 1,75 trilhão (R$ 9 trilhões), essa é maior oferta pública inicial de ações (IPO, na sigla em inglês) da história. Diante da alta demanda, bolsas de valores ao redor do mundo passaram a oferecer ati…', 'https://g1.globo.com/economia/noticia/2026/06/12/spacex-brasileiros.ghtml', 'G1 Economia', '2026-06-12T14:18:08', 14, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (124, 'Por que a economia faz desta Copa a mais ''louca'' de todos os tempos', 'Os torcedores estão sendo pressionados como nunca porque este torneio segue um modelo econômico muito diferente dos anteriores AFP via Getty Images As edições da Copa do Mundo de futebol raramente são completamente isentas de política, mas nunca o futebol precisou se equilibrar em uma corda bamba geopolítica como esta. O principal país-sede (Estados Unidos) está em guerra com um participante (Irã), cuja equipe precisa se deslocar a partir de outro país-sede (México) nos dias de jogo. Baixe o GloboPop para assistir a vídeos curtos verticais da Globo Soma-se a isso a coincidência impressionante…', 'https://g1.globo.com/economia/noticia/2026/06/12/por-que-a-economia-faz-desta-copa-a-mais-louca-de-todos-os-tempos.ghtml', 'G1 Economia', '2026-06-12T14:01:35', 7, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (126, 'Preço dos alimentos em maio: o que ficou mais caro e o que barateou no mês', 'Inflação desacelera para 0,58% em maio, mas segue acima da meta e alimentos pressionam IPCA O Índice Nacional de Preços ao Consumidor Amplo (IPCA), considerado a inflação oficial do país, subiu 0,58% em maio, uma desaceleração em relação a abril, quando os preços haviam avançado 0,67%, mostram dados do IBGE, divulgados nesta sexta-feira (12). Apesar da desaceleração, os preços dos alimentos continuam pressionando a inflação. Sozinho, o grupo de Alimentação e Bebibas respondeu por 0,29 ponto percentual do IPCA, ao registrar alta de 1,33%. Os alimentos consumidos em casa ficaram, em média, 1,65%…', 'https://g1.globo.com/economia/agronegocios/noticia/2026/06/12/preco-dos-alimentos-em-maio-o-que-ficou-mais-caro-e-o-que-barateou.ghtml', 'G1 Economia', '2026-06-12T12:58:36', 2, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (128, 'IPCA: preços sobem 0,58% em maio, mas alimentação em casa tem maior alta para o mês em 18 anos', 'Inflação desacelera para 0,58% em maio, mas segue acima da meta e alimentos pressionam IPCA O Índice Nacional de Preços ao Consumidor Amplo (IPCA), considerado a inflação oficial do país, subiu 0,58% em maio, segundo dados divulgados nesta sexta-feira (12) pelo Instituto Brasileiro de Geografia e Estatística (IBGE). 🗒️Tem alguma sugestão de reportagem? Mande para o g1 Mesmo com uma desaceleração em relação aos 0,67% registrados em abril, a inflação acumulada em 12 meses subiu de 4,39% para 4,72%. No acumulado do ano, o IPCA soma 3,20%. Em maio do ano passado, a inflação oficial havia registrad…', 'https://g1.globo.com/economia/noticia/2026/06/12/ipca-inflacao-maio.ghtml', 'G1 Economia', '2026-06-12T12:00:49', 5, TRUE);
INSERT INTO noticias (id, titulo, resumo, link, fonte, data_publicacao, score_economico, em_escopo) VALUES (129, 'Dólar cai a R$ 5,06, de olho em inflação no Brasil e Oriente Médio; Ibovespa recua', 'Entenda o que faz o preço do dólar subir ou cair O dólar inverteu o sinal positivo visto pela manhã e fechou em queda de 0,77% nesta sexta-feira (12), cotado a R$ 5,0618.Já o Ibovespa, principal índice da bolsa brasileira, recuou 0,21%, aos 171.132 pontos. 🗒️ Tem alguma sugestão de reportagem? Envie para o g1 ▶️ Os novos dados da inflação brasileira estão no centro das atenções nesta sexta-feira. O índice subiu 0,58% em maio, em desaceleração em relação a abril (0,67%). Os dados reforçam a expectativa pela Superquarta da próxima semana, momento em que o Banco Central do Brasil (BC) e o Federal…', 'https://g1.globo.com/economia/noticia/2026/06/12/dolar-ibovespa.ghtml', 'G1 Economia', '2026-06-12T12:00:15', 12, TRUE);
